import React from "react";
import { Link as LinkRouter } from "react-router-dom" 

export default function CardsCities({filter}) {
    return (
    <>
        {filter.map(city => (
            <Card sx={{ maxWidth: 345 }}>
                <CardMedia
                component="img"
                height="140"
                image={city.image}
                alt="green iguana"
                />
                <CardContent>
                <Typography gutterBottom variant="h5" component="div">{city.cityname}</Typography>

                <Typography gutterBottom variant="h6" component="div">{city.country}</Typography>


                </CardContent>
                <CardActions>
                <Button size="small">Learn More</Button>
                </CardActions>
            </Card>
        ))}
    </>
    );
}
